package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.tools.AntigravityToolMapper
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager

/**
 * Handles tool call events (start, result) from Antigravity.
 */
class ToolCallEventHandler(
    private val stateManager: StreamingStateManager,
    private val onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit
) {
    fun handleToolCallStart(event: RemoteEvent.ToolCallStart, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false

        val normalizedName = AntigravityToolMapper.mapToolName(event.name)
        val normalizedArgs = AntigravityToolMapper.mapToolArgs(event.name, event.arguments)
        val uiMeta = AntigravityToolMapper.getUiMetadata(event.name, event.arguments)

        val status = when (event.status.uppercase()) {
            "PENDING", "WAITING", "STANDBY" -> ToolStatus.PENDING
            "RUNNING" -> ToolStatus.RUNNING
            "SUCCESS" -> ToolStatus.SUCCESS
            "ERROR"   -> ToolStatus.ERROR
            else      -> ToolStatus.RUNNING
        }

        val toolExec = ToolExecution(
            toolCallId = event.toolCallId,
            name = normalizedName,
            arguments = normalizedArgs,
            status = status,
            metadata = mapOf(
                "source" to "remote",
                "animateOnMount" to "true"
            ),
            uiMetadata = uiMeta
        )

        onUiStateUpdate { state ->
            val finalizedMsgs = finalizeRunningThinkingOnLastAssistant(state.messages)
            val updatedMsgs = updateToolInMessages(finalizedMsgs, event.toolCallId) { tool ->
                tool.copy(
                    name = normalizedName,
                    arguments = normalizedArgs,
                    status = status,
                    metadata = tool.metadata + ("source" to "remote"),
                    uiMetadata = uiMeta
                )
            } ?: run {
                val msgs = ensureAssistantMessage(finalizedMsgs, force = false)
                updateLastAssistantMessage(msgs) { msg ->
                    msg.copy(
                        toolExecutions = msg.toolExecutions + toolExec,
                        isThinking = false
                    )
                }
            }
            state.copy(messages = updatedMsgs)
        }
        return true
    }

    fun handleToolActivity(event: RemoteEvent.ToolActivity, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        if (!event.type.equals("terminal", ignoreCase = true)) return false
        val chunk = event.terminalData
        if (chunk.isBlank()) return true

        onUiStateUpdate { state ->
            val updated = appendTerminalChunkToLatestRunningShellTool(state.messages, chunk)
            state.copy(messages = updated)
        }
        return true
    }

    fun handleToolCallResult(event: RemoteEvent.ToolCallResult, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        val extractedResult = AntigravityToolMapper.extractToolResult(event.result)

        onUiStateUpdate { state ->
            val updatedMsgs = updateToolInMessages(state.messages, event.toolCallId) { tool ->
                val isPlaceholder = extractedResult.trim().equals("done", ignoreCase = true) ||
                    extractedResult.trim().equals("success", ignoreCase = true)
                val hasStreamedOutput = !tool.result.isNullOrBlank()

                tool.copy(
                    result = if (tool.name.equals("run_shell", ignoreCase = true) && hasStreamedOutput && isPlaceholder) {
                        tool.result
                    } else {
                        extractedResult
                    },
                    status = if (event.isError) ToolStatus.ERROR else ToolStatus.SUCCESS
                )
            } ?: state.messages
            state.copy(messages = updatedMsgs)
        }
        return true
    }

    private fun isForActiveConversation(eventConversationId: String?, currentConversationId: String?): Boolean {
        if (eventConversationId.isNullOrBlank()) return true
        if (currentConversationId.isNullOrBlank()) return true
        return eventConversationId == currentConversationId
    }

    private fun finalizeRunningThinkingOnLastAssistant(messages: List<UiMessage>): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val msg = messages[idx]
        if (!hasSyntheticThinkingTool(msg)) return messages

        val updatedTools = msg.toolExecutions.map { tool ->
            if ((tool.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                    tool.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)) &&
                tool.status == ToolStatus.RUNNING
            ) {
                tool.copy(status = ToolStatus.SUCCESS)
            } else {
                tool
            }
        }
        return messages.toMutableList().apply { this[idx] = msg.copy(toolExecutions = updatedTools) }
    }

    private fun hasSyntheticThinkingTool(message: UiMessage): Boolean {
        return message.toolExecutions.any {
            it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                it.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)
        }
    }

    private fun ensureAssistantMessage(messages: List<UiMessage>, force: Boolean): List<UiMessage> {
        val lastMsg = messages.lastOrNull()

        // Check for an existing empty assistant placeholder before the early-return,
        // otherwise this check would be dead code (role == ASSISTANT already handled above).
        val hasAssistantPlaceholder = lastMsg?.role == MessageRole.ASSISTANT &&
            lastMsg.content.isBlank() &&
            lastMsg.thinking.isNullOrBlank() &&
            lastMsg.toolExecutions.isEmpty()

        if (lastMsg?.role == MessageRole.ASSISTANT) return messages
        if (!force && hasAssistantPlaceholder) return messages

        return messages + UiMessage(role = MessageRole.ASSISTANT, content = "")
    }

    private fun updateLastAssistantMessage(
        messages: List<UiMessage>,
        update: (UiMessage) -> UiMessage
    ): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val updated = messages.toMutableList()
        updated[idx] = update(updated[idx])
        return updated
    }

    private fun updateToolInMessages(
        messages: List<UiMessage>,
        toolCallId: String,
        update: (ToolExecution) -> ToolExecution
    ): List<UiMessage>? {
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            val toolIdx = msg.toolExecutions.indexOfFirst { it.toolCallId == toolCallId }
            if (toolIdx != -1) {
                val updatedTools = msg.toolExecutions.toMutableList()
                updatedTools[toolIdx] = update(updatedTools[toolIdx])
                return messages.toMutableList().apply { this[i] = msg.copy(toolExecutions = updatedTools) }
            }
        }
        return null
    }

    private fun appendTerminalChunkToLatestRunningShellTool(messages: List<UiMessage>, chunk: String): List<UiMessage> {
        val sanitizedChunk = chunk
        // Walk backwards so we update the latest relevant tool execution.
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            if (msg.role != MessageRole.ASSISTANT) continue

            val toolIdx = msg.toolExecutions.indexOfLast {
                it.name.equals("run_shell", ignoreCase = true) &&
                    (it.status == ToolStatus.RUNNING || it.status == ToolStatus.PENDING)
            }
            if (toolIdx == -1) continue

            val tools = msg.toolExecutions.toMutableList()
            val existing = tools[toolIdx].result ?: ""
            val merged = if (existing.isBlank()) sanitizedChunk else (existing + sanitizedChunk)
            tools[toolIdx] = tools[toolIdx].copy(result = merged)
            val updatedMsg = msg.copy(toolExecutions = tools)
            return messages.toMutableList().apply { this[i] = updatedMsg }
        }
        return messages
    }
}

package com.amaya.intelligence.impl.ide.antigravity.client

import android.content.Context
import com.amaya.intelligence.domain.models.MessageAttachment
import dagger.hilt.android.qualifiers.ApplicationContext
import javax.inject.Inject
import javax.inject.Singleton
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import org.java_websocket.client.WebSocketClient
import org.java_websocket.handshake.ServerHandshake
import org.json.JSONArray
import org.json.JSONObject
import java.net.URI
import java.util.ArrayDeque
import com.amaya.intelligence.domain.models.ConnectionState

/**
 * WebSocket client that connects to Antigravity IDE extension server.
 * Receives chat state, streaming text, tool calls from Antigravity.
 * Sends user commands (send message, new chat, etc.) to Antigravity.
 *
 * This is a pure remote display client — no AI processing happens here.
 * All AI configuration, model selection, and processing is done by Antigravity.
 */
@Singleton
class RemoteSessionClient @Inject constructor(
    @ApplicationContext context: Context
) {
    private var wsClient: WebSocketClient? = null
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val appContext: Context = context.applicationContext
    private val prefs = appContext.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    private var lastIp: String? = null
    private var lastPort: Int? = null
    private var isManualDisconnect = false
    private var reconnectJob: Job? = null
    private var postConnectRefreshJob: Job? = null
    @Volatile private var reconnecting = false
    private var lastSeqId = -1
    private var lastServerSessionId: String? = null
    private var reconnectDelay = INITIAL_RECONNECT_DELAY

    private val localStreamingHint: MutableMap<String, Boolean> = mutableMapOf()
    private val pendingCommands: ArrayDeque<String> = ArrayDeque()
    private val maxPendingCommands = 64
    private var lastForegroundUpdateAt = 0L
    private val minForegroundUpdateInterval = 1200L // Rate limit updates to ~1Hz

    companion object {
        private const val PREFS_NAME = "amaya_remote_session"
        private const val KEY_LAST_IP = "last_ip"
        private const val KEY_LAST_PORT = "last_port"
        private const val KEY_LAST_SEQ_ID = "last_seq_id"
        private const val KEY_LAST_SERVER_SESSION_ID = "last_server_session_id"
        private const val INITIAL_RECONNECT_DELAY = 1000L
    }

    init {
        lastIp = prefs?.getString(KEY_LAST_IP, null)
        lastPort = prefs?.getInt(KEY_LAST_PORT, 0)?.takeIf { it > 0 }
        lastSeqId = prefs?.getInt(KEY_LAST_SEQ_ID, -1) ?: -1
        lastServerSessionId = prefs?.getString(KEY_LAST_SERVER_SESSION_ID, null)
    }

    // Connection state
    private val _connectionState = MutableStateFlow(ConnectionState.DISCONNECTED)
    val connectionState: StateFlow<ConnectionState> = _connectionState.asStateFlow()

    // Incoming events from Antigravity
    private val _events = MutableSharedFlow<RemoteEvent>(extraBufferCapacity = 256)
    val events: SharedFlow<RemoteEvent> = _events.asSharedFlow()

    // Error messages
    private val _errorMessage = MutableStateFlow<String?>(null)
    val errorMessage: StateFlow<String?> = _errorMessage.asStateFlow()

    // Server info
    private val _serverInfo = MutableStateFlow<String?>(null)
    val serverInfo: StateFlow<String?> = _serverInfo.asStateFlow()

    @Synchronized
    fun connect(ip: String, port: Int, isReconnect: Boolean = false) {
        if (!isReconnect) {
            isManualDisconnect = false
            reconnectJob?.cancel()
            reconnectJob = null
            reconnectDelay = INITIAL_RECONNECT_DELAY
        }
        
        // If we're already connecting/connected to THIS ip/port, don't restart unless forced.
        if (lastIp == ip && lastPort == port && _connectionState.value != ConnectionState.DISCONNECTED) {
            android.util.Log.v("RemoteSessionClient", "Already connecting/connected to $ip:$port, skipping redundant connect")
            return
        }

        lastIp = ip
        lastPort = port
        prefs?.edit()?.putString(KEY_LAST_IP, ip)?.putInt(KEY_LAST_PORT, port)?.apply()

        android.util.Log.i("RemoteSessionClient", "Connecting to $ip:$port (isReconnect=$isReconnect)")
        
        postConnectRefreshJob?.cancel()
        postConnectRefreshJob = null
        
        disconnectInternal()

        _connectionState.value = ConnectionState.CONNECTING
        _errorMessage.value = null

        val uri = URI("ws://$ip:$port")
        val newClient = object : WebSocketClient(uri) {
            override fun onOpen(handshakedata: ServerHandshake?) {
                if (this@RemoteSessionClient.wsClient != this) return
                android.util.Log.i("RemoteSessionClient", "WebSocket onOpen: $ip:$port")
                
                _connectionState.value = ConnectionState.CONNECTED
                _serverInfo.value = "$ip:$port"
                _errorMessage.value = null
                runCatching { RemoteSessionForegroundService.start(appContext) }
                runCatching { RemoteSessionForegroundService.updateStatus(appContext, RemoteSessionForegroundService.STATE_CONNECTED) }
                reconnecting = false
                reconnectDelay = INITIAL_RECONNECT_DELAY
                
                flushPendingCommands()
                forceResync(resetSequence = true)
            }

            override fun onMessage(message: String?) {
                message ?: return
                this@RemoteSessionClient.onMessage(message)
            }

            override fun onClose(code: Int, reason: String?, remote: Boolean) {
                if (this@RemoteSessionClient.wsClient != this) {
                    android.util.Log.v("RemoteSessionClient", "Stale WebSocket onClose ignored")
                    return
                }
                android.util.Log.w("RemoteSessionClient", "WebSocket onClose: code=$code, reason=$reason, remote=$remote, manual=$isManualDisconnect")

                _connectionState.value = ConnectionState.DISCONNECTED
                runCatching { RemoteSessionForegroundService.stop(appContext) }
                if (!isManualDisconnect) {
                    val error = "Connection lost: ${reason ?: "unknown"} ($code)"
                    _errorMessage.value = "$error. Reconnecting..."
                    attemptReconnect()
                }
            }

            override fun onError(ex: Exception?) {
                if (this@RemoteSessionClient.wsClient != this) return
                android.util.Log.e("RemoteSessionClient", "WebSocket onError: ${ex?.message}")
                _errorMessage.value = "Connection error: ${ex?.message ?: "unknown"}"
            }
        }

        wsClient = newClient
        newClient.connectionLostTimeout = 10
        newClient.connect()
    }

    private fun onMessage(message: String) {
        runCatching {
            val json = JSONObject(message)
            val type = json.optString("event").takeIf { it.isNotBlank() } 
                ?: json.optString("type").takeIf { it.isNotBlank() } 
                ?: return@runCatching
            
            android.util.Log.v("RemoteSessionClient", "Received message: $type (seq=${json.optInt("seqId", -1)})")

            // Update session ID if present (check both serverSessionId and sessionId)
            val sid = json.optNullableString("serverSessionId") ?: json.optNullableString("sessionId")
            sid?.let { newSid ->
                if (newSid != lastServerSessionId) {
                    android.util.Log.i(
                        "RemoteSessionClient",
                        "Server session changed ($lastServerSessionId -> $newSid). Resetting seq cursor."
                    )
                    lastServerSessionId = newSid
                    prefs?.edit()?.putString(KEY_LAST_SERVER_SESSION_ID, newSid)?.apply()
                    lastSeqId = -1 // Reset sequence on new session
                    prefs?.edit()?.putInt(KEY_LAST_SEQ_ID, -1)?.apply()
                }
            }

            val seqId = json.optInt("seqId", -1)
            if (shouldSkipEvent(seqId, sid ?: lastServerSessionId)) return@runCatching
            if (seqId > lastSeqId) {
                lastSeqId = seqId
                prefs?.edit()?.putInt(KEY_LAST_SEQ_ID, lastSeqId)?.apply()
            }

            // Handle Heartbeat
            if (type == "ping") {
                sendRawMessage(JSONObject().put("action", "pong").toString(), queueIfDisconnected = false)
                return@runCatching
            }

            val event = parseEvent(json)
            if (event != null) {
                updateForegroundStatus(event)
                val cid = event.conversationId
                if (cid != null) {
                    // Update streaming hints based on event type
                    when (event) {
                        is RemoteEvent.ToolCallStart,
                        is RemoteEvent.AiThinking,
                        is RemoteEvent.TitleGenerated -> {
                            if (localStreamingHint[cid] != true) {
                                localStreamingHint[cid] = true
                                _events.tryEmit(RemoteEvent.StateUpdate(isLoading = false, isStreaming = true, seqId = 0, conversationId = cid))
                            }
                        }
                        is RemoteEvent.TextDelta -> {
                            if (localStreamingHint[cid] != true) {
                                localStreamingHint[cid] = true
                                _events.tryEmit(RemoteEvent.StateUpdate(isLoading = false, isStreaming = true, seqId = 0, conversationId = cid))
                            }
                        }
                        is RemoteEvent.StreamDone,
                        is RemoteEvent.Error -> {
                            localStreamingHint[cid] = false
                            _events.tryEmit(RemoteEvent.StateUpdate(isLoading = false, isStreaming = false, seqId = 0, conversationId = cid))
                        }
                        is RemoteEvent.StateUpdate -> {
                            if (!event.isStreaming) localStreamingHint[cid] = false
                        }
                        is RemoteEvent.StateSync -> {
                            localStreamingHint[cid] = event.isStreaming
                        }
                        else -> Unit
                    }
                }
                _events.tryEmit(event)
            }
        }.onFailure { ex ->
            android.util.Log.e("RemoteSessionClient", "Error processing message: ${ex.message}", ex)
        }
    }

    private fun shouldSkipEvent(seqId: Int, currentSessionId: String?): Boolean {
        // If seqId is -1 (not present or invalid), always process.
        // If currentSessionId is null (no session established yet), always process.
        // If the session ID has changed, we've already reset lastSeqId, so process.
        if (seqId == -1 || currentSessionId == null || currentSessionId != lastServerSessionId) {
            return false
        }
        // Only skip if it's a positive seqId we've already seen in the same session.
        return seqId > 0 && seqId <= lastSeqId
    }

    private fun attemptReconnect() {
        if (isManualDisconnect) return
        val ip = lastIp ?: return
        val port = lastPort ?: return

        // Single-flight reconnect: don't start another loop if one is already running.
        if (reconnecting && reconnectJob?.isActive == true) return

        reconnectJob?.cancel()
        reconnecting = true
        reconnectJob = scope.launch {
            try {
                while (isActive && !isManualDisconnect && _connectionState.value != ConnectionState.CONNECTED) {
                    // Avoid repeatedly creating sockets while a connect is already in progress.
                    if (_connectionState.value == ConnectionState.CONNECTING) {
                        delay(250)
                        continue
                    }

                    val jitter = (0..350).random().toLong()
                    val delayMs = (reconnectDelay + jitter).coerceAtMost(30000L)
                    delay(delayMs)

                    if (!isActive || isManualDisconnect) break
                    if (_connectionState.value == ConnectionState.CONNECTED) break

                    try {
                        connect(ip, port, isReconnect = true)
                    } catch (_: Exception) {}

                    // Wait a bit for the connection attempt to succeed before escalating backoff.
                    withTimeoutOrNull(6000L) {
                        while (isActive && _connectionState.value == ConnectionState.CONNECTING) {
                            delay(150)
                        }
                    }

                    if (_connectionState.value != ConnectionState.CONNECTED) {
                        reconnectDelay = (reconnectDelay * 2).coerceAtMost(15000L)
                    }
                }
            } finally {
                reconnecting = false
            }
        }
    }

    fun disconnect() {
        isManualDisconnect = true
        reconnectJob?.cancel()
        reconnecting = false
        disconnectInternal()
    }

    private fun disconnectInternal() {
        try {
            wsClient?.close()
        } catch (_: Exception) {}
        wsClient = null
        _connectionState.value = ConnectionState.DISCONNECTED
        _serverInfo.value = null
        runCatching { RemoteSessionForegroundService.stop(appContext) }
    }

    // ── Commands to Antigravity ──────────────────────────────────

    fun sendMessage(content: String, conversationId: String? = null, mode: String? = null, attachments: List<RemoteAttachment> = emptyList()) {
        android.util.Log.d("RemoteSessionClient", "sendMessage: content=${content.take(50)}..., attachments=${attachments.size}")
        attachments.forEachIndexed { idx, att ->
            android.util.Log.d("RemoteSessionClient", "Attachment[$idx]: mimeType=${att.mimeType}, dataLen=${att.dataBase64.length}, fileName=${att.fileName}")
        }
        sendCommand("send_message", JSONObject().apply {
            put("content", content)
            if (conversationId != null) {
                put("conversationId", conversationId)
                put("id", conversationId) // Backwards compat
            }
            if (!mode.isNullOrBlank()) {
                put("mode", mode)
            }
            if (attachments.isNotEmpty()) {
                put("attachments", JSONArray().apply {
                    attachments.forEach { attachment ->
                        put(JSONObject().apply {
                            put("mimeType", attachment.mimeType)
                            put("dataBase64", attachment.dataBase64)
                            if (attachment.fileName.isNotBlank()) {
                                put("fileName", attachment.fileName)
                            }
                        })
                    }
                })
            }
        })
    }

    fun stopGeneration(conversationId: String? = null) {
        sendCommand("stop_generation", JSONObject().apply {
            if (!conversationId.isNullOrBlank()) {
                put("conversationId", conversationId)
                put("id", conversationId)
            }
        })
    }

    fun respondToToolInteraction(
        toolCallId: String,
        accepted: Boolean,
        conversationId: String? = null,
        name: String? = null,
        arguments: Map<String, Any?> = emptyMap(),
        metadata: Map<String, String> = emptyMap()
    ) {
        sendCommand("tool_interaction", JSONObject().apply {
            put("toolCallId", toolCallId)
            put("accepted", accepted)
            if (!conversationId.isNullOrBlank()) {
                put("conversationId", conversationId)
                put("id", conversationId)
            }
            if (!name.isNullOrBlank()) {
                put("name", name)
            }
            put("arguments", JSONObject().apply {
                arguments.forEach { (key, value) -> put(key, value ?: JSONObject.NULL) }
            })
            put("metadata", JSONObject().apply {
                metadata.forEach { (key, value) -> put(key, value) }
            })
        })
    }

    fun newChat() {
        sendCommand("new_chat")
    }

    fun getModels() {
        sendCommand("get_models")
    }

    fun selectModel(modelId: String) {
        sendCommand("select_model", JSONObject().apply {
            put("modelId", modelId)
        })
    }

    fun switchConversation(conversationId: String) {
        sendCommand("switch_conversation", JSONObject().apply {
            put("conversationId", conversationId)
        })
    }

    fun getConversations() {
        sendCommand("get_conversations")
    }

    fun openAgent() {
        sendCommand("open_agent")
    }

    fun refreshState() {
        if (lastSeqId > 0) {
            sendRawMessage(
                JSONObject().apply {
                    put("action", "get_events_since")
                    put("data", JSONObject().put("lastSeqId", lastSeqId))
                }.toString()
            )
        }
        sendCommand("get_state")
    }

    fun forceResync(resetSequence: Boolean = true) {
        if (resetSequence) {
            lastSeqId = 0
            prefs?.edit()?.putInt(KEY_LAST_SEQ_ID, 0)?.apply()
        }
        sendCommand("get_state")
        getModels()
        getConversations()
        getWorkspaces()
    }

    fun loadConversation(id: String) {
        sendCommand("load_conversation", JSONObject().apply {
            put("id", id)
        })
    }

    fun confirmAction(confirmed: Boolean) {
        sendCommand("confirm_action", JSONObject().apply {
            put("confirmed", confirmed)
        })
    }

    fun getWorkspaces() {
        sendCommand("get_workspaces")
    }

    fun getProjectFiles(path: String = "") {
        sendCommand("get_project_files", JSONObject().put("path", path))
    }

    fun getFileDiff() {
        sendCommand("get_file_diff")
    }

    fun getFileContent(path: String) {
        sendCommand("get_file_content", JSONObject().put("path", path))
    }

    fun setConversationMode(mode: com.amaya.intelligence.domain.models.ConversationMode) {
        sendCommand("set_conversation_mode", JSONObject().put("mode", mode.wireValue))
    }

    private fun sendCommand(action: String, data: JSONObject? = null) {
        val msg = JSONObject().apply {
            put("action", action)
            if (data != null) {
                put("data", data)
            }
        }
        sendRawMessage(msg.toString())
    }

    private fun sendRawMessage(payload: String, queueIfDisconnected: Boolean = true) {
        val client = wsClient
        if (client != null && client.isOpen) {
            try {
                client.send(payload)
                return
            } catch (_: Exception) {
            }
        }

        if (queueIfDisconnected) {
            enqueuePendingCommand(payload)
        }
    }

    private fun enqueuePendingCommand(payload: String) {
        val action = extractAction(payload)
        if (action != null && isIdempotentAction(action)) {
            val kept = ArrayDeque<String>()
            while (pendingCommands.isNotEmpty()) {
                val existing = pendingCommands.removeFirst()
                val existingAction = extractAction(existing)
                if (existingAction == action) continue
                kept.addLast(existing)
            }
            pendingCommands.addAll(kept)
        }

        while (pendingCommands.size >= maxPendingCommands) {
            if (pendingCommands.isNotEmpty()) {
                pendingCommands.removeFirst()
            }
        }
        pendingCommands.addLast(payload)
    }

    private fun extractAction(payload: String): String? {
        return try {
            JSONObject(payload).optString("action", "").takeIf { it.isNotBlank() }
        } catch (_: Exception) {
            null
        }
    }

    private fun isIdempotentAction(action: String): Boolean {
        return action == "get_state" ||
            action == "get_models" ||
            action == "get_conversations" ||
            action == "get_workspaces" ||
            action == "get_project_files"
    }

    private fun flushPendingCommands() {
        val client = wsClient ?: return
        while (client.isOpen && pendingCommands.isNotEmpty()) {
            val payload = pendingCommands.removeFirst()
            try {
                client.send(payload)
            } catch (_: Exception) {
                pendingCommands.addFirst(payload)
                break
            }
        }
    }

    // ── Parse incoming events ────────────────────────────────────

    private fun parseEvent(json: JSONObject): RemoteEvent? {
        val data = json.optJSONObject("data")
        val seqId = json.optInt("seqId", 0)
        val conversationId = data?.optString("conversationId", "")?.takeIf { it.isNotBlank() } 
            ?: json.optString("conversationId", "").takeIf { it.isNotBlank() }
        val serverIp = json.optNullableString("serverIp")
        
        val eventType = json.optString("event").takeIf { it.isNotBlank() } ?: json.optString("type")
        return when (eventType) {
            "state_sync" -> {
                data ?: return null
                val cw = data.optJSONObject("currentWorkspace")
                RemoteEvent.StateSync(
                    messages = parseMessages(data.optJSONArray("messages")),
                    isLoading = data.optBoolean("isLoading", false),
                    isStreaming = data.optBoolean("isStreaming", false),
                    currentModel = data.optString("currentModel", ""),
                    toolExecutions = parseToolExecutions(data.optJSONArray("toolExecutions")),
                    conversationMode = data.optNullableString("conversationMode"),
                    appName = data.optString("appName", "Antigravity"),
                    appVersion = data.optString("appVersion", ""),
                    currentWorkspace = if (cw != null) RemoteWorkspace(
                        name = cw.optString("name", ""),
                        path = cw.optString("path", ""),
                        isCurrent = true
                    ) else null,
                    seqId = seqId,
                    conversationId = conversationId,
                    serverIp = serverIp
                )
            }
            "state_update" -> {
                data ?: return null
                RemoteEvent.StateUpdate(
                    isLoading = data.optBoolean("isLoading", false),
                    isStreaming = data.optBoolean("isStreaming", false),
                    seqId = seqId,
                    conversationId = conversationId,
                    serverIp = serverIp
                )
            }
            "text_delta" -> {
                data ?: return null
                RemoteEvent.TextDelta(data.optString("text", ""), seqId = seqId, conversationId = conversationId)
            }
            "stream_progress" -> {
                data ?: return null
                RemoteEvent.StreamProgress(
                    conversationId = conversationId ?: data.optString("conversationId", ""),
                    sizeDelta = data.optInt("sizeDelta", 0),
                    totalGrowth = data.optInt("totalGrowth", 0),
                    seqId = seqId
                )
            }
            "tool_call_start" -> {
                data ?: return null
                RemoteEvent.ToolCallStart(
                    toolCallId = data.optString("toolCallId", ""),
                    name = data.optString("name", ""),
                    arguments = parseArguments(data.optJSONObject("arguments")),
                    metadata = parseStringMap(data.optJSONObject("metadata")),
                    status = data.optString("status", "RUNNING"),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "tool_call_result" -> {
                data ?: return null
                RemoteEvent.ToolCallResult(
                    toolCallId = data.optString("toolCallId", ""),
                    result = data.optString("result", ""),
                    isError = data.optBoolean("isError", false),
                    seqId = seqId,
                    conversationId = conversationId,
                    serverIp = serverIp
                )
            }
            "tool_activity" -> {
                data ?: return null
                RemoteEvent.ToolActivity(
                    type = data.optString("type", ""),
                    // Extension may send terminal name under `name` instead of `file`
                    file = when {
                        data.has("file") && data.optString("file").isNotBlank() -> data.optString("file", "")
                        data.has("name") && data.optString("name").isNotBlank() -> data.optString("name", "")
                        else -> ""
                    },
                    terminalData = data.optString("data", ""),
                    seqId = seqId,
                    conversationId = conversationId,
                    serverIp = serverIp
                )
            }
            "stream_done" -> {
                val reason = data?.optString("stopReason", "NATURAL_TERMINATION")
                RemoteEvent.StreamDone(stopReason = reason, seqId = seqId, conversationId = conversationId)
            }
            "error" -> {
                data ?: return null

                val message = when {
                    data.has("message") && data.optString("message").isNotBlank() -> data.optString("message")
                    data.has("raw") && data.optString("raw").isNotBlank() -> data.optString("raw")
                    else -> data.toString()
                }

                RemoteEvent.Error(
                    message = humanizeErrorMessage(message),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "confirmation_required" -> {
                data ?: return null
                RemoteEvent.ConfirmationRequired(
                    title = data.optString("title", ""),
                    description = data.optString("description", ""),
                    riskLevel = data.optString("riskLevel", "medium"),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "new_assistant_message" -> RemoteEvent.NewAssistantMessage(seqId = seqId, conversationId = conversationId)
            "new_conversation" -> RemoteEvent.NewConversation(seqId = seqId, conversationId = conversationId, serverIp = serverIp)
            "ai_thinking" -> {
                data ?: return null
                RemoteEvent.AiThinking(
                    text = data.optString("text", ""),
                    stepIndex = data.optString("stepIndex", ""),
                    isRunning = data.optBoolean("isRunning", true),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "title_generated" -> {
                data ?: return null
                RemoteEvent.TitleGenerated(
                    title = data.optString("title", ""),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "status_change" -> {
                data ?: return null
                val status = data.optString("status", "")
                RemoteEvent.StatusChange(
                    status = status,
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "external_activity" -> {
                data ?: return null
                RemoteEvent.ExternalActivity(
                    conversationId = conversationId ?: data.optString("conversationId", ""),
                    seqId = seqId
                )
            }
            "debug_log" -> {
                data ?: return null
                RemoteEvent.DebugLog(
                    message = data.optString("message", ""),
                    timestamp = data.optLong("timestamp", 0L),
                    seqId = seqId,
                    conversationId = conversationId
                )
            }
            "user_message" -> {
                data ?: return null
                val attachmentsArr = data.optJSONArray("attachments")
                val attachments = mutableListOf<MessageAttachment>()
                if (attachmentsArr != null) {
                    for (i in 0 until attachmentsArr.length()) {
                        val a = attachmentsArr.optJSONObject(i) ?: continue
                        attachments.add(MessageAttachment(
                            mimeType = a.optString("mimeType", ""),
                            dataBase64 = a.optString("dataBase64", a.optString("inlineData", "")),
                            fileName = a.optString("fileName", "")
                        ))
                    }
                }
                RemoteEvent.UserMessage(data.optString("content", ""), attachments, seqId = seqId, conversationId = conversationId)
            }
            "conversations_list" -> {
                data ?: return null
                val convArr = data.optJSONArray("conversations")
                val list = mutableListOf<RemoteConversationMeta>()
                if (convArr != null) {
                    for (i in 0 until convArr.length()) {
                        val c = convArr.optJSONObject(i) ?: continue
                        list.add(RemoteConversationMeta(
                            id = c.optString("id", ""),
                            lastModified = c.optLong("lastModified", 0),
                            size = c.optLong("size", 0),
                            title = c.optString("title", ""),
                            preview = c.optString("preview", ""),
                            workspacePath = c.optString("workspacePath", "")
                        ))
                    }
                }
                RemoteEvent.ConversationsList(list, data.optNullableString("currentWorkspacePath"), seqId = seqId, conversationId = conversationId)
            }
            "models_list" -> {
                data ?: return null
                val modelArr = data.optJSONArray("models")
                val selectedModelId = data.optString("selectedModelId", "")
                val list = mutableListOf<RemoteModelInfo>()
                if (modelArr != null) {
                    for (i in 0 until modelArr.length()) {
                        val m = modelArr.optJSONObject(i) ?: continue
                        val quotaInfo = m.optJSONObject("quotaInfo")
                        val quota = when {
                            m.has("quota") -> m.optDouble("quota", 1.0)
                            quotaInfo != null -> quotaInfo.optDouble("remainingFraction", 1.0)
                            else -> 1.0
                        }
                        val resetTime = m.optNullableString("resetTime")
                            ?: quotaInfo?.optNullableString("resetTime")
                        list.add(RemoteModelInfo(
                            id = m.optString("id", ""),
                            label = m.optString("label", ""),
                            isRecommended = m.optBoolean("isRecommended", false),
                            quota = quota,
                            resetTime = resetTime,
                            tagTitle = m.optNullableString("tagTitle"),
                            supportsImages = m.optBoolean("supportsImages", false)
                        ))
                    }
                }
                RemoteEvent.ModelsList(list, selectedModelId, seqId = seqId, conversationId = conversationId)
            }
            "conversation_loaded" -> {
                data ?: return null
                RemoteEvent.ConversationLoaded(
                    conversationId = conversationId ?: data.optString("conversationId", ""),
                    messages = parseMessages(data.optJSONArray("messages")),
                    conversationMode = data.optNullableString("conversationMode"),
                    seqId = seqId,
                    serverIp = serverIp
                )
            }
            "model_selected" -> {
                data ?: return null
                RemoteEvent.ModelSelected(data.optString("modelId", ""), seqId = seqId, conversationId = conversationId)
            }
            "workspaces_list" -> {
                data ?: return null
                val wsArr = data.optJSONArray("workspaces")
                val list = mutableListOf<RemoteWorkspace>()
                if (wsArr != null) {
                    for (i in 0 until wsArr.length()) {
                        val w = wsArr.optJSONObject(i) ?: continue
                        list.add(RemoteWorkspace(
                            name = w.optString("name", ""),
                            path = w.optString("path", ""),
                            isCurrent = w.optBoolean("isCurrent", false)

package com.amaya.intelligence.impl.ide.antigravity.tools

import com.amaya.intelligence.impl.common.mappers.ToolUiMapper
import com.amaya.intelligence.domain.models.ToolUiMetadata

/**
 * Antigravity-specific tool name and argument mapper.
 *
 * Maps Antigravity's internal step type names (CORTEX_STEP_TYPE_*) to
 * Amaya's standard tool names used by ToolCallCard and ToolResultPreview.
 */
object AntigravityToolMapper {

    private fun firstNonNull(map: Map<String, Any?>, vararg keys: String): Any? {
        keys.forEach { key ->
            if (map.containsKey(key)) {
                val value = map[key]
                if (value != null && value.toString().isNotBlank()) return value
            }
        }
        return null
    }

    /**
     * Maps the raw tool name from Antigravity to a normalized name.
     */
    fun mapToolName(rawName: String): String = when (rawName) {
        // File operations
        "CORTEX_STEP_TYPE_READ_FILE",
        "view_file", "view_file_outline", "view_code_item"
            -> "read_file"

        "CORTEX_STEP_TYPE_WRITE_FILE",
        "write_to_file"
            -> "write_file"

        "CORTEX_STEP_TYPE_EDIT_FILE",
        "replace_file_content", "multi_replace_file_content"
            -> "edit_file"

        // Shell / terminal
        "CORTEX_STEP_TYPE_RUN_COMMAND",
        "run_command"
            -> "run_shell"

        "command_status" -> "check_status_terminal"
        "send_command_input" -> "send_command_input"
        "read_terminal" -> "read_terminal"

        // Search / find
        "CORTEX_STEP_TYPE_SEARCH",
        "grep_search", "find_by_name"
            -> "find_files"

        "list_dir" -> "list_files"

        // Browser / web tools
        "browser_subagent",
        "read_url_content", "search_web"
            -> "browser"

        // Task management
        "task_boundary" -> "task_boundary"
        "notify_user"   -> "notify_user"

        // Image generation
        "generate_image" -> "generate_image"

        // MCP tools
        else -> {
            if (rawName.startsWith("mcp_")) rawName
            else rawName
        }
    }

    /**
     * Normalizes arguments based on the mapped tool name.
     */
    fun mapToolArgs(toolName: String, args: Map<String, Any?>): Map<String, Any?> {
        val normalizedName = mapToolName(toolName)
        val mapped = args.toMutableMap()

        mapped["summary"] = firstNonNull(
            mapped,
            "summary",
            "Summary",
            "Description",
            "description",
            "Instruction",
            "instruction",
            "TaskSummary",
            "taskSummary"
        )

        when (normalizedName) {
            "run_shell" -> {
                mapped["command"] = firstNonNull(
                    mapped,
                    "command",
                    "CommandLine",
                    "commandLine",
                    "submittedCommandLine",
                    "proposedCommandLine",
                    "cmd"
                ) ?: mapped.values.firstOrNull()?.toString()
                mapped["cwd"] = firstNonNull(mapped, "cwd", "Cwd", "DirectoryPath", "searchPath")
            }
            "check_status_terminal" -> {
                mapped["commandId"] = firstNonNull(mapped, "commandId", "CommandId", "ProcessID", "processId", "PID")
                mapped["waitSeconds"] = firstNonNull(mapped, "waitSeconds", "WaitDurationSeconds", "WaitTime") ?: "0"
                mapped["maxChars"] = firstNonNull(mapped, "maxChars", "OutputCharacterCount", "MaxChars")
            }
            "send_command_input" -> {
                mapped["command"] = "Input " + (mapped["Input"] ?: mapped["CommandId"] ?: "")
            }
            "read_terminal" -> {
                mapped["command"] = "Read " + (mapped["ProcessID"] ?: "")
            }
            "read_file" -> {
                mapped["path"] = firstNonNull(mapped, "path", "AbsolutePath", "absolutePath", "File", "file", "filePath")
            }
            "write_file" -> {
                mapped["path"] = firstNonNull(mapped, "path", "TargetFile", "targetFile", "filePath")
                mapped["targetContent"] = firstNonNull(mapped, "targetContent", "TargetContent")
                mapped["replacementContent"] = firstNonNull(mapped, "replacementContent", "ReplacementContent", "CodeContent", "codeContent")
                mapped["replacementChunks"] = firstNonNull(mapped, "replacementChunks", "ReplacementChunks")
            }
            "edit_file" -> {
                mapped["path"] = firstNonNull(mapped, "path", "TargetFile", "targetFile", "filePath")
                mapped["targetContent"] = firstNonNull(mapped, "targetContent", "TargetContent")
                mapped["replacementContent"] = firstNonNull(mapped, "replacementContent", "ReplacementContent", "CodeContent", "codeContent")
                mapped["replacementChunks"] = firstNonNull(mapped, "replacementChunks", "ReplacementChunks")
            }
            "find_files" -> {
                mapped["query"] = firstNonNull(mapped, "query", "Query", "content")
                mapped["path"] = firstNonNull(mapped, "path", "SearchPath", "searchPath", "SearchDirectory", "searchDirectory")
                mapped["pattern"] = mapped["Pattern"] ?: mapped["pattern"]
            }
            "list_files" -> {
                mapped["path"] = firstNonNull(mapped, "path", "DirectoryPath", "directoryPath")
            }
            "browser" -> {
                mapped["task"] = mapped["Task"] ?: mapped["task"] ?: mapped["Url"] ?: mapped["url"] ?: mapped["query"] ?: mapped["task"]
            }
            "view_code_item" -> {
                mapped["path"] = mapped["File"] ?: mapped["file"] ?: mapped["filePath"] ?: mapped["path"]
            }
            "read_url_content" -> {
                mapped["task"] = mapped["Url"] ?: mapped["url"] ?: mapped["task"]
            }
            "search_web" -> {
                mapped["task"] = mapped["query"] ?: mapped["Query"] ?: mapped["task"]
            }
            "task_boundary" -> {
                mapped["title"] = mapped["TaskName"] ?: mapped["taskName"] ?: mapped["title"]
                mapped["summary"] = mapped["TaskSummary"] ?: mapped["taskSummary"] ?: mapped["summary"]
                mapped["taskStatus"] = mapped["TaskStatus"] ?: mapped["taskStatus"] ?: mapped["status_text"]
            }
            "notify_user" -> {
                mapped["content"] = mapped["Message"] ?: mapped["message"] ?: mapped["content"]
            }
            "generate_image" -> {
                mapped["prompt"] = mapped["Prompt"] ?: mapped["prompt"]
            }
        }

        // Map generic metadata that applies to all tools
        if (mapped["complexity"] == null) mapped["complexity"] = mapped["Complexity"] ?: mapped["complexity"]
        if (mapped["content"] == null) mapped["content"] = mapped["Description"] ?: mapped["description"] ?: mapped["Instruction"] ?: mapped["instruction"]

        // Ensure original_name is preserved
        mapped["original_name"] = args["original_name"] ?: toolName

        return mapped
    }

    /**
     * Gets UI metadata for rendering.
     */
    fun getUiMetadata(toolName: String, args: Map<String, Any?>, metadata: Map<String, String>? = null): ToolUiMetadata {
        val normalizedName = mapToolName(toolName)
        val normalizedArgs = mapToolArgs(toolName, args)
        return ToolUiMapper.getToolUiMetadata(normalizedName, normalizedArgs, metadata)
    }

    /**
     * Extracts a human-readable result from raw data.
     */
    fun extractToolResult(rawData: Any?): String {
        return when (rawData) {
            is String -> rawData
            is Map<*, *> -> {
                (rawData["output"] ?: rawData["result"] ?: rawData.toString()).toString()
            }
            null -> ""
            else -> rawData.toString()
        }
    }
}

package com.amaya.intelligence.impl.ide.antigravity.services

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.domain.ai.IntelligenceService
import com.amaya.intelligence.domain.ai.IntelligenceSessionManager
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteSessionClient
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteEvent
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteAttachment
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteFileEntry as ClientRemoteFileEntry
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteWorkspace as ClientRemoteWorkspace
import com.amaya.intelligence.data.local.db.entity.ConversationEntity
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager
import com.amaya.intelligence.impl.ide.antigravity.services.event.AntigravityEventHandler
import com.amaya.intelligence.di.ApplicationScope
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import javax.inject.Inject
import javax.inject.Singleton

/**
 * Antigravity implementation of IntelligenceService.
 * Wraps RemoteSessionClient and delegates event handling to AntigravityEventHandler.
 */
@Singleton
class AntigravityIntelligenceService @Inject constructor(
    private val client: RemoteSessionClient,
    @ApplicationScope private val scope: CoroutineScope
) : IntelligenceService {

    private val _uiState = MutableStateFlow(ChatUiState(
        sessionMode = IntelligenceSessionManager.SessionMode.ANTIGRAVITY
    ))
    override val uiState: StateFlow<ChatUiState> = _uiState.asStateFlow()

    private val _conversations = MutableStateFlow<List<ConversationEntity>>(emptyList())
    override val conversations: StateFlow<List<ConversationEntity>> = _conversations.asStateFlow()

    private val _projectFiles = MutableStateFlow<List<ProjectFileEntry>>(emptyList())
    override val projectFiles: StateFlow<List<ProjectFileEntry>> = _projectFiles.asStateFlow()

    private val _projectPath = MutableStateFlow("")
    override val projectPath: StateFlow<String> = _projectPath.asStateFlow()

    private val _workspaces = MutableStateFlow<List<RemoteWorkspace>>(emptyList())
    override val workspaces: StateFlow<List<RemoteWorkspace>> = _workspaces.asStateFlow()

    private val stateManager = StreamingStateManager()
    private var hasBootstrappedRemoteWorkspace = false

    private val eventHandler = AntigravityEventHandler(
        scope = scope,
        client = client,
        stateManager = stateManager,
        onUiStateUpdate = { update -> _uiState.update(update) },
        onConversationsUpdate = { entities -> _conversations.value = entities },
        onProjectFilesUpdate = { files, path -> 
            _projectFiles.value = files
            _projectPath.value = path
        },
        onWorkspacesUpdate = { workspaces -> _workspaces.value = workspaces }
    )

    init {
        scope.launch {
            client.events.collect { event ->
                eventHandler.handleEvent(event, _uiState.value.conversationId)
            }
        }
        // Monitor connection state
        scope.launch {
            client.connectionState.collect { state ->
                _uiState.update { it.copy(connectionState = state) }
                if (state == ConnectionState.CONNECTED) {
                    if (!hasBootstrappedRemoteWorkspace) {
                        hasBootstrappedRemoteWorkspace = true
                        client.getWorkspaces()
                        _uiState.value.workspacePath?.takeIf { it.isNotBlank() }?.let { client.getProjectFiles(it) }
                    }
                    resync()
                }
            }
        }
    }

    override fun sendMessage(content: String) {
        val activeId = _uiState.value.conversationId
        val mode = _uiState.value.conversationMode.wireValue
        client.sendMessage(content, activeId, mode)

        // Optimistic update
        val userMsg = UiMessage(
            role = MessageRole.USER,
            content = content
        )
        _uiState.update { it.copy(messages = it.messages + userMsg, isLoading = true) }
    }

    override fun sendMessageWithImage(content: String, imageBase64: String, mimeType: String, fileName: String) {
        android.util.Log.d("AntigravityIntelligenceService", "sendMessageWithImage: content=${content.take(50)}, mimeType=$mimeType, base64Len=${imageBase64.length}, fileName=$fileName")
        val activeId = _uiState.value.conversationId
        val mode = _uiState.value.conversationMode.wireValue
        val attachment = RemoteAttachment(mimeType, imageBase64, fileName)
        client.sendMessage(content, activeId, mode, listOf(attachment))

        // Optimistic update with image attachment
        val userMsg = UiMessage(
            role = MessageRole.USER,
            content = content,
            attachments = listOf(MessageAttachment(mimeType, imageBase64, fileName))
        )
        _uiState.update { it.copy(messages = it.messages + userMsg, isLoading = true) }
    }

    override fun stopGeneration() {
        client.stopGeneration()
    }

    override fun clearConversation() {
        client.newChat()
    }

    override fun loadConversation(id: String) {
        val resolvedId = eventHandler.resolveConversationId(id)
        _uiState.update { it.copy(conversationId = resolvedId, isLoading = true) }
        client.loadConversation(resolvedId)
    }

    override fun deleteConversation(id: String) {
        // Antigravity might not support deletion via client yet, or needs mapping
    }

    override fun setSelectedAgent(agentId: String) {
        client.selectModel(agentId)
    }

    override fun getProjectFiles(path: String) {
        client.getProjectFiles(path)
    }

    override fun respondToToolInteraction(executionId: String, confirmed: Boolean) {
        val conversationId = _uiState.value.conversationId
        client.respondToToolInteraction(
            toolCallId = executionId,
            accepted = confirmed,
            conversationId = conversationId
        )
    }

    override fun setWorkspace(path: String?) {
        _uiState.update { it.copy(workspacePath = path) }
        path?.let { client.getProjectFiles(it) }
    }

    override fun clearError() {
        _uiState.update { it.copy(error = null) }
    }

    override fun connect(ip: String, port: Int) {
        client.connect(ip, port)
    }

    override fun resync() {
        client.forceResync(resetSequence = true)
    }

    override fun refreshState() {
        client.refreshState()
    }

    override fun setConversationMode(mode: ConversationMode) {
        _uiState.update { it.copy(conversationMode = mode) }
        client.setConversationMode(mode)
    }

    override fun refreshModels() {
        client.getModels()
    }

    override fun loadMoreConversations() {
        // Implementation for pagination if needed
    }

    override fun hasMoreConversations(): Boolean {
        return false
    }
}

// Extension to map remote models to domain
private fun ClientRemoteFileEntry.toProjectFileEntry(): ProjectFileEntry {
    return ProjectFileEntry(
        name = name,
        path = path,
        type = type,
        size = size
    )
}

private fun ClientRemoteWorkspace.toDomainWorkspace(): RemoteWorkspace {
    return RemoteWorkspace(
        name = name,
        path = path,
        isCurrent = isCurrent
    )
}

package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.services.mapper.AntigravityMessageMapper
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager

/**
 * Handles message events (user message, new assistant message) from Antigravity.
 */
class MessageEventHandler(
    private val stateManager: StreamingStateManager,
    private val onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit
) {
    fun handleNewAssistantMessage(event: RemoteEvent.NewAssistantMessage, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        onUiStateUpdate { state ->
            state.copy(messages = startNewAssistantMessage(state.messages))
        }
        return true
    }

    fun handleUserMessage(event: RemoteEvent.UserMessage, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        onUiStateUpdate { state ->
            val normalizedIncoming = AntigravityMessageMapper.normalizeUserText(event.content)
            val hasRecentDuplicate = state.messages
                .takeLast(8)
                .any { it.role == MessageRole.USER && AntigravityMessageMapper.normalizeUserText(it.content) == normalizedIncoming }

            if (hasRecentDuplicate) {
                state.copy(isLoading = false)
            } else {
                val msgs = state.messages.toMutableList()
                val lastMsg = msgs.lastOrNull()
                val hasEmptyAssistantPlaceholder = lastMsg?.role == MessageRole.ASSISTANT &&
                    lastMsg.content.isBlank() &&
                    lastMsg.thinking.isNullOrBlank() &&
                    lastMsg.toolExecutions.isEmpty()

                val userMsg = UiMessage(
                    role = MessageRole.USER, 
                    content = event.content,
                    attachments = event.attachments
                )

                if (hasEmptyAssistantPlaceholder) {
                    msgs.add((msgs.size - 1).coerceAtLeast(0), userMsg)
                } else {
                    msgs.add(userMsg)
                }
                state.copy(messages = msgs, isLoading = false)
            }
        }
        return true
    }

    private fun isForActiveConversation(eventConversationId: String?, currentConversationId: String?): Boolean {
        if (eventConversationId.isNullOrBlank()) return true
        if (currentConversationId.isNullOrBlank()) return true
        return eventConversationId == currentConversationId
    }

    private fun startNewAssistantMessage(messages: List<UiMessage>): List<UiMessage> {
        val lastMsg = messages.lastOrNull()
        val hasAssistantPlaceholder = lastMsg?.role == MessageRole.ASSISTANT &&
            lastMsg.content.isBlank() &&
            lastMsg.thinking.isNullOrBlank() &&
            lastMsg.toolExecutions.isEmpty()

        stateManager.clearAll()

        if (hasAssistantPlaceholder) {
            val updated = messages.toMutableList()
            val idx = updated.indexOfLast { it.role == MessageRole.ASSISTANT }
            if (idx != -1) {
                updated[idx] = lastMsg.copy(isThinking = false)
            }
            return updated
        }

        return messages + UiMessage(role = MessageRole.ASSISTANT, content = "")
    }
}

package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.services.mapper.AntigravityMessageMapper
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager

/**
 * Handles streaming events (text delta, AI thinking, stream done) from Antigravity.
 */
class StreamingEventHandler(
    private val stateManager: StreamingStateManager,
    private val onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit
) {
    fun handleTextDelta(event: RemoteEvent.TextDelta, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false

        onUiStateUpdate { state ->
            val lastAssistant = state.messages.lastOrNull()
            if (lastAssistant?.role == MessageRole.ASSISTANT &&
                lastAssistant.content.isBlank() &&
                hasSyntheticThinkingTool(lastAssistant)
            ) {
                val updatedMsgs = finalizeRunningThinkingOnLastAssistant(state.messages)
                val withNewBubble = ensureAssistantMessage(updatedMsgs, force = true)
                val merged = stateManager.mergeStreamingSegment(event.text)
                return@onUiStateUpdate state.copy(
                    messages = updateLastAssistantContent(withNewBubble, merged, null, false, null)
                )
            }

            val msgs = ensureAssistantMessage(state.messages, force = false)
            stateManager.setPhase(StreamingStateManager.StreamPhase.TEXT)
            val merged = stateManager.mergeStreamingSegment(event.text)
            state.copy(messages = updateLastAssistantContent(msgs, merged, null, false, null))
        }
        return true
    }

    fun handleAiThinking(event: RemoteEvent.AiThinking, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false

        stateManager.setPhase(StreamingStateManager.StreamPhase.TOOL)

        if (event.stepIndex.isNotBlank() && event.stepIndex != stateManager.currentStepIndex) {
            stateManager.clearThinking()
            stateManager.setStepIndex(event.stepIndex)
        }

        if (event.text.isNotBlank()) {
            stateManager.setThinking(event.text)
        }

        onUiStateUpdate { state ->
            state.copy(messages = upsertThinkingToolOnLastAssistant(
                state.messages, 
                stateManager.currentThinking, 
                event.isRunning, 
                stateManager.currentStepIndex ?: ""
            ))
        }
        return true
    }

    fun handleStreamDone(event: RemoteEvent.StreamDone, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        onUiStateUpdate { state ->
            val finalizedMsgs = finalizeRunningThinkingOnLastAssistant(state.messages)
            state.copy(isStreaming = false, isLoading = false, messages = finalizedMsgs)
        }
        stateManager.clearAll()
        return true
    }

    private fun isForActiveConversation(eventConversationId: String?, currentConversationId: String?): Boolean {
        if (eventConversationId.isNullOrBlank()) return true
        if (currentConversationId.isNullOrBlank()) return true
        return eventConversationId == currentConversationId
    }

    private fun hasSyntheticThinkingTool(message: UiMessage): Boolean {
        return message.toolExecutions.any {
            it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                it.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)
        }
    }

    private fun finalizeRunningThinkingOnLastAssistant(messages: List<UiMessage>): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val msg = messages[idx]
        if (!hasSyntheticThinkingTool(msg)) return messages

        val updatedTools = msg.toolExecutions.map { tool ->
            if ((tool.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                    tool.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)) &&
                tool.status == ToolStatus.RUNNING
            ) {
                tool.copy(status = ToolStatus.SUCCESS)
            } else {
                tool
            }
        }
        return messages.toMutableList().apply { this[idx] = msg.copy(toolExecutions = updatedTools) }
    }

    private fun ensureAssistantMessage(messages: List<UiMessage>, force: Boolean): List<UiMessage> {
        val lastMsg = messages.lastOrNull()
        if (lastMsg?.role == MessageRole.ASSISTANT) return messages

        val hasAssistantPlaceholder = lastMsg?.role == MessageRole.ASSISTANT &&
            lastMsg.content.isBlank() &&
            lastMsg.thinking.isNullOrBlank() &&
            lastMsg.toolExecutions.isEmpty()

        if (!force && hasAssistantPlaceholder) return messages

        return messages + UiMessage(role = MessageRole.ASSISTANT, content = "")
    }

    private fun updateLastAssistantContent(
        messages: List<UiMessage>,
        content: String,
        thinking: String?,
        isThinking: Boolean,
        thinkingStartedAt: Long?
    ): List<UiMessage> {
        val idx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (idx == -1) return messages

        val updated = messages.toMutableList()
        updated[idx] = updated[idx].copy(
            content = content,
            thinking = thinking,
            isThinking = isThinking,
            thinkingStartedAt = thinkingStartedAt
        )
        return updated
    }

    private fun upsertThinkingToolOnLastAssistant(
        messages: List<UiMessage>,
        thinkingText: String,
        isRunning: Boolean,
        stepIndex: String
    ): List<UiMessage> {
        val sanitized = thinkingText.trim()
        if (sanitized.isEmpty()) return messages

        val searchId = if (stepIndex.isNotBlank()) "thinking-$stepIndex" else null

        // Search backwards for existing thinking tool
        for (i in messages.indices.reversed()) {
            val msg = messages[i]
            if (msg.role != MessageRole.ASSISTANT) continue

            val existingIdx = msg.toolExecutions.indexOfFirst {
                (searchId != null && it.toolCallId == searchId) ||
                    (it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" &&
                        it.result?.trim()?.lowercase() == sanitized.lowercase())
            }

            if (existingIdx >= 0) {
                val updatedTools = msg.toolExecutions.toMutableList()
                val thoughtTitle = AntigravityMessageMapper.extractThoughtTitle(sanitized)
                val updatedMeta = updatedTools[existingIdx].metadata.toMutableMap()
                if (thoughtTitle != null) {
                    updatedMeta["thoughtTitle"] = thoughtTitle
                }

                val updatedUiMeta = updatedTools[existingIdx].uiMetadata?.copy(
                    label = thoughtTitle ?: updatedTools[existingIdx].uiMetadata?.label ?: "Thinking"
                )

                updatedTools[existingIdx] = updatedTools[existingIdx].copy(
                    result = sanitized,
                    status = if (isRunning) ToolStatus.RUNNING else ToolStatus.SUCCESS,
                    metadata = updatedMeta,
                    uiMetadata = updatedUiMeta
                )
                return messages.toMutableList().apply { this[i] = msg.copy(toolExecutions = updatedTools) }
            }
        }

        // Not found, add to last assistant message
        val lastAssistantIdx = messages.indexOfLast { it.role == MessageRole.ASSISTANT }
        if (lastAssistantIdx >= 0) {
            val msg = messages[lastAssistantIdx]
            val updatedTools = msg.toolExecutions.toMutableList()
            val thinkingToolId = searchId ?: "thinking:${msg.id}:${System.currentTimeMillis()}"

            val thoughtTitle = AntigravityMessageMapper.extractThoughtTitle(sanitized)
            val meta = mutableMapOf(
                StreamingStateManager.THINKING_TOOL_META_KEY to "true",
                "syntheticThinking" to "true",
                "source" to "remote"
            )
            if (thoughtTitle != null) {
                meta["thoughtTitle"] = thoughtTitle
            }

            updatedTools.add(ToolExecution(
                toolCallId = thinkingToolId,
                name = StreamingStateManager.THINKING_TOOL_NAME,
                arguments = mapOf("source" to "ai_thinking_stream"),
                result = sanitized,
                status = if (isRunning) ToolStatus.RUNNING else ToolStatus.SUCCESS,
                metadata = meta,
                uiMetadata = ToolUiMetadata(
                    category = ToolCategory.TASK_MANAGEMENT,
                    label = thoughtTitle ?: "Thinking",
                    actionIcon = ToolInfoIcon.BRAIN,
                    targetIcon = ToolInfoIcon.GENERATE,
                    badges = listOf("THINKING")
                )
            ))
            return messages.toMutableList().apply { this[lastAssistantIdx] = msg.copy(toolExecutions = updatedTools) }
        }

        return messages
    }
}

package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.client.RemoteWorkspace as ClientRemoteWorkspace
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager
import com.amaya.intelligence.data.local.db.entity.ConversationEntity
import kotlinx.coroutines.CoroutineScope

/**
 * Main event handler that delegates to specialized sub-handlers.
 * Coordinates event handling across state sync, streaming, tool calls, messages, workspace, and errors.
 */
class AntigravityEventHandler(
    scope: CoroutineScope,
    client: RemoteSessionClient,
    private val stateManager: StreamingStateManager,
    onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit,
    onConversationsUpdate: (List<ConversationEntity>) -> Unit,
    onProjectFilesUpdate: (List<ProjectFileEntry>, String) -> Unit,
    onWorkspacesUpdate: (List<com.amaya.intelligence.domain.models.RemoteWorkspace>) -> Unit
) {
    private val stateSyncHandler = StateSyncEventHandler(stateManager, onUiStateUpdate)
    private val streamingHandler = StreamingEventHandler(stateManager, onUiStateUpdate)
    private val toolCallHandler = ToolCallEventHandler(stateManager, onUiStateUpdate)
    private val messageHandler = MessageEventHandler(stateManager, onUiStateUpdate)
    private val workspaceHandler = WorkspaceEventHandler(onUiStateUpdate, onConversationsUpdate, onProjectFilesUpdate, onWorkspacesUpdate, client)
    private val errorHandler = ErrorEventHandler(scope, client, stateManager, onUiStateUpdate)

    fun handleEvent(event: RemoteEvent, currentConversationId: String?) {
        runCatching {
            when (event) {
                is RemoteEvent.StateSync -> stateSyncHandler.handleStateSync(event, currentConversationId)
                is RemoteEvent.ConversationLoaded -> stateSyncHandler.handleConversationLoaded(event)
                is RemoteEvent.StateUpdate -> stateSyncHandler.handleStateUpdate(event, currentConversationId)
                is RemoteEvent.TextDelta -> streamingHandler.handleTextDelta(event, currentConversationId)
                is RemoteEvent.AiThinking -> streamingHandler.handleAiThinking(event, currentConversationId)
                is RemoteEvent.NewAssistantMessage -> messageHandler.handleNewAssistantMessage(event, currentConversationId)
                is RemoteEvent.UserMessage -> messageHandler.handleUserMessage(event, currentConversationId)
                is RemoteEvent.ToolCallStart -> toolCallHandler.handleToolCallStart(event, currentConversationId)
                is RemoteEvent.ToolCallResult -> toolCallHandler.handleToolCallResult(event, currentConversationId)
                is RemoteEvent.ToolActivity -> toolCallHandler.handleToolActivity(event, currentConversationId)
                is RemoteEvent.ConversationsList -> workspaceHandler.handleConversationsList(event)
                is RemoteEvent.ModelSelected -> workspaceHandler.handleModelSelected(event)
                is RemoteEvent.ActiveConversation -> workspaceHandler.handleActiveConversation(event, currentConversationId, stateManager)
                is RemoteEvent.CurrentWorkspace -> workspaceHandler.handleCurrentWorkspace(event)
                is RemoteEvent.StreamDone -> streamingHandler.handleStreamDone(event, currentConversationId)
                is RemoteEvent.NewConversation -> workspaceHandler.handleNewConversation(event, stateManager)
                is RemoteEvent.ProjectFiles -> workspaceHandler.handleProjectFiles(event)
                is RemoteEvent.WorkspacesList -> workspaceHandler.handleWorkspacesList(event)
                is RemoteEvent.ModelsList -> workspaceHandler.handleModelsList(event)
                is RemoteEvent.TitleGenerated -> workspaceHandler.handleTitleGenerated(event)
                is RemoteEvent.Error -> errorHandler.handleError(event, currentConversationId)
                else -> {}
            }
        }.onFailure { ex ->
            android.util.Log.e("AntigravityEventHandler", "Error in handleEvent: ${ex.message}", ex)
        }
    }

    fun resolveConversationId(id: String): String {
        return workspaceHandler.resolveConversationId(id)
    }
}

package com.amaya.intelligence.impl.ide.antigravity.services.streaming

/**
 * Manages streaming state for Antigravity intelligence service.
 * Tracks current phase, accumulated text, and thinking content during streaming.
 */
class StreamingStateManager {

    enum class StreamPhase {
        NONE, THINKING, TEXT, TOOL
    }

    private val streamingText = StringBuilder()
    private val streamingThinking = StringBuilder()
    private var streamingMessageId: String? = null
    private var currentStreamPhase: StreamPhase = StreamPhase.NONE
    private var lastStreamingStepIndex: String? = null

    val currentText: String get() = streamingText.toString()
    val currentThinking: String get() = streamingThinking.toString()
    val currentPhase: StreamPhase get() = currentStreamPhase
    val currentStepIndex: String? get() = lastStreamingStepIndex

    fun setPhase(phase: StreamPhase) {
        currentStreamPhase = phase
    }

    fun setStepIndex(index: String?) {
        lastStreamingStepIndex = index
    }

    fun appendText(text: String) {
        streamingText.append(text)
    }

    fun setText(text: String) {
        streamingText.clear()
        streamingText.append(text)
    }

    fun setThinking(text: String) {
        streamingThinking.clear()
        streamingThinking.append(text)
    }

    fun clearThinking() {
        streamingThinking.clear()
    }

    fun clearText() {
        streamingText.clear()
    }

    fun clearAll() {
        streamingText.clear()
        streamingThinking.clear()
        streamingMessageId = null
        currentStreamPhase = StreamPhase.NONE
        lastStreamingStepIndex = null
    }

    fun mergeStreamingSegment(incoming: String): String {
        val current = streamingText.toString()
        if (incoming.isBlank()) return current
        if (current.isBlank()) {
            streamingText.clear()
            streamingText.append(incoming)
            return incoming
        }
        if (incoming.startsWith(current)) {
            streamingText.clear()
            streamingText.append(incoming)
            return incoming
        }
        if (current.endsWith(incoming)) return current

        val merged = current + incoming
        streamingText.clear()
        streamingText.append(merged)
        return merged
    }

    companion object {
        const val THINKING_TOOL_NAME = "thinking"
        const val THINKING_TOOL_META_KEY = "syntheticThinking"
    }
}

package com.amaya.intelligence.impl.ide.antigravity.services.event

import com.amaya.intelligence.data.remote.api.MessageRole
import com.amaya.intelligence.domain.models.*
import com.amaya.intelligence.impl.ide.antigravity.client.*
import com.amaya.intelligence.impl.ide.antigravity.services.mapper.AntigravityMessageMapper
import com.amaya.intelligence.impl.ide.antigravity.services.streaming.StreamingStateManager

/**
 * Handles state synchronization events from Antigravity.
 */
class StateSyncEventHandler(
    private val stateManager: StreamingStateManager,
    private val onUiStateUpdate: ((ChatUiState) -> ChatUiState) -> Unit
) {
    fun handleStateSync(event: RemoteEvent.StateSync, currentConversationId: String?) {
        val serverConversationId = event.conversationId

        if (!serverConversationId.isNullOrBlank() && serverConversationId != currentConversationId) {
            stateManager.clearAll()
        }

        val messages = AntigravityMessageMapper.mapRemoteMessages(event.messages, event.isStreaming)
        onUiStateUpdate { state ->
            var finalMessages = if (state.isStreaming && event.isStreaming && messages.isNotEmpty() && state.messages.isNotEmpty()) {
                val lastLocal = state.messages.last()
                val lastIncoming = messages.lastOrNull()
                val canOverlayLocalAssistant = shouldOverlayLocalAssistant(lastLocal, lastIncoming)

                if (canOverlayLocalAssistant) {
                    messages.dropLast(1) + lastLocal
                } else messages
            } else messages

            // Keep optimistic user prompt visible while streaming until server echo catches up.
            if (event.isStreaming && state.messages.isNotEmpty()) {
                val localTrailingUsers = state.messages
                    .takeLastWhile { it.role == MessageRole.USER && it.content.isNotBlank() }

                if (localTrailingUsers.isNotEmpty()) {
                    val incomingUsers = finalMessages
                        .asReversed()
                        .filter { it.role == MessageRole.USER }
                        .take(12)
                        .map { AntigravityMessageMapper.normalizeUserText(it.content) }
                        .toSet()

                    val missingUsers = localTrailingUsers.filter {
                        val normalized = AntigravityMessageMapper.normalizeUserText(it.content)
                        normalized.isNotBlank() && normalized !in incomingUsers
                    }

                    if (missingUsers.isNotEmpty()) {
                        val lastAssistant = finalMessages.lastOrNull()?.takeIf { it.role == MessageRole.ASSISTANT }
                        finalMessages = if (lastAssistant != null) {
                            finalMessages.dropLast(1) + missingUsers + lastAssistant
                        } else {
                            finalMessages + missingUsers
                        }
                    }
                }
            }

            // If the server's state sync messages don't include attachments (common for media),
            // preserve local attachments so image previews don't disappear when idle.
            finalMessages = mergeMissingAttachmentsFromLocal(state.messages, finalMessages)
            finalMessages = preserveLocalAttachmentMessages(state.messages, finalMessages)

            state.copy(
                conversationId = serverConversationId ?: state.conversationId,
                messages = finalMessages,
                isLoading = event.isLoading,
                isStreaming = event.isStreaming,
                selectedModel = event.currentModel.ifBlank { state.selectedModel },
                error = null,
                serverIp = event.serverIp ?: state.serverIp
            )
        }
        if (!event.isStreaming) {
            stateManager.clearAll()
        }
    }

    fun handleConversationLoaded(event: RemoteEvent.ConversationLoaded) {
        val messages = AntigravityMessageMapper.mapRemoteMessages(event.messages, isStreaming = false)
        onUiStateUpdate { state ->
            var merged = mergeMissingAttachmentsFromLocal(state.messages, messages)
            merged = preserveLocalUserMessages(state.messages, merged)
            merged = preserveLocalAttachmentMessages(state.messages, merged)
            state.copy(
                conversationId = event.conversationId,
                messages = merged,
                isLoading = false,
                isStreaming = false,
                serverIp = event.serverIp ?: state.serverIp
            )
        }
        stateManager.clearAll()
    }

    fun handleStateUpdate(event: RemoteEvent.StateUpdate, currentConversationId: String?): Boolean {
        if (!isForActiveConversation(event.conversationId, currentConversationId)) return false
        onUiStateUpdate { it.copy(
            isLoading = event.isLoading,
            isStreaming = event.isStreaming,
            serverIp = event.serverIp ?: it.serverIp
        ) }
        if (!event.isStreaming) {
            stateManager.clearAll()
        }
        return true
    }

    private fun isForActiveConversation(eventConversationId: String?, currentConversationId: String?): Boolean {
        if (eventConversationId.isNullOrBlank()) return true
        if (currentConversationId.isNullOrBlank()) return true
        return eventConversationId == currentConversationId
    }

    private fun shouldOverlayLocalAssistant(localLast: UiMessage, incomingLast: UiMessage?): Boolean {
        if (localLast.role != MessageRole.ASSISTANT) return false

        val localHasText = localLast.content.isNotBlank()
        val incomingHasText = incomingLast?.role == MessageRole.ASSISTANT && incomingLast.content.isNotBlank()
        if (localHasText && (!incomingHasText || localLast.content.length > (incomingLast?.content?.length ?: 0))) {
            return true
        }

        val localThinkingRunning = isRunningSyntheticThinking(localLast)
        val incomingThinkingRunning = isRunningSyntheticThinking(incomingLast)
        if (localThinkingRunning) {
            val localThinking = syntheticThinkingText(localLast)
            val incomingThinking = syntheticThinkingText(incomingLast)
            if (!incomingThinkingRunning || localThinking.length > incomingThinking.length) {
                return true
            }
        }

        return false
    }

    private fun mergeMissingAttachmentsFromLocal(
        local: List<UiMessage>,
        incoming: List<UiMessage>
    ): List<UiMessage> {
        if (incoming.isEmpty() || local.isEmpty()) return incoming

        // Map latest local USER message attachments by normalized content
        val localByNormalized = LinkedHashMap<String, UiMessage>()
        local.asReversed().forEach { msg ->
            if (msg.role != MessageRole.USER) return@forEach
            if (msg.attachments.isEmpty()) return@forEach
            val key = AntigravityMessageMapper.normalizeUserText(msg.content)
            if (key.isBlank()) return@forEach
            if (!localByNormalized.containsKey(key)) {
                localByNormalized[key] = msg
            }
        }

        if (localByNormalized.isEmpty()) return incoming

        return incoming.map { msg ->
            if (msg.role != MessageRole.USER) return@map msg
            if (msg.attachments.isNotEmpty()) return@map msg
            val key = AntigravityMessageMapper.normalizeUserText(msg.content)
            val localMatch = localByNormalized[key]
            if (localMatch != null) msg.copy(attachments = localMatch.attachments) else msg
        }
    }

    private fun preserveLocalAttachmentMessages(
        local: List<UiMessage>,
        incoming: List<UiMessage>
    ): List<UiMessage> {
        if (local.isEmpty()) return incoming

        // Build a set of normalized incoming user contents for quick membership checks.
        val incomingUserKeys = incoming
            .filter { it.role == MessageRole.USER }
            .map { AntigravityMessageMapper.normalizeUserText(it.content) }
            .filter { it.isNotBlank() }
            .toSet()

        // Keep local user messages with attachments that are not present in incoming.
        val missingAttachmentUsers = local
            .takeLast(20)
            .filter { it.role == MessageRole.USER && it.attachments.isNotEmpty() }
            .filter {
                val key = AntigravityMessageMapper.normalizeUserText(it.content)
                key.isNotBlank() && key !in incomingUserKeys
            }

        if (missingAttachmentUsers.isEmpty()) return incoming

        val lastAssistant = incoming.lastOrNull()?.takeIf { it.role == MessageRole.ASSISTANT }
        return if (lastAssistant != null) {
            incoming.dropLast(1) + missingAttachmentUsers + lastAssistant
        } else {
            incoming + missingAttachmentUsers
        }
    }

    private fun preserveLocalUserMessages(
        local: List<UiMessage>,
        incoming: List<UiMessage>
    ): List<UiMessage> {
        if (local.isEmpty()) return incoming

        val localUsers = local
            .takeLastWhile { it.role == MessageRole.USER && it.content.isNotBlank() }

        if (localUsers.isEmpty()) return incoming

        val incomingUserKeys = incoming
            .filter { it.role == MessageRole.USER }
            .map { AntigravityMessageMapper.normalizeUserText(it.content) }
            .filter { it.isNotBlank() }
            .toSet()

        val missingUsers = localUsers.filter {
            val normalized = AntigravityMessageMapper.normalizeUserText(it.content)
            normalized.isNotBlank() && normalized !in incomingUserKeys
        }

        if (missingUsers.isEmpty()) return incoming

        val lastAssistant = incoming.lastOrNull()?.takeIf { it.role == MessageRole.ASSISTANT }
        return if (lastAssistant != null) {
            incoming.dropLast(1) + missingUsers + lastAssistant
        } else {
            incoming + missingUsers
        }
    }

    private fun isRunningSyntheticThinking(message: UiMessage?): Boolean {
        if (message == null) return false
        return message.toolExecutions.any {
            (it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                it.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)) &&
                it.status == ToolStatus.RUNNING
        }
    }

    private fun syntheticThinkingText(message: UiMessage?): String {
        if (message == null) return ""
        return message.toolExecutions.firstOrNull {
            it.metadata[StreamingStateManager.THINKING_TOOL_META_KEY] == "true" ||
                it.name.equals(StreamingStateManager.THINKING_TOOL_NAME, ignoreCase = true)
        }?.result?.trim().orEmpty()
    }
}

