242:     private fun shouldSkipEvent(seqId: Int, currentSessionId: String?): Boolean {
243:         // If seqId is -1 (not present or invalid), always process.
244:         // If currentSessionId is null (no session established yet), always process.
245:         // If the session ID has changed, we've already reset lastSeqId, so process.
246:         if (seqId == -1 || currentSessionId == null || currentSessionId != lastServerSessionId) {
247:             return false
248:         }
249:         // Only skip if it's a positive seqId we've already seen in the same session.
250:         return seqId > 0 && seqId <= lastSeqId
251:     }
