493:     private fun enqueuePendingCommand(payload: String) {
494:         val action = extractAction(payload)
495:         if (action != null && isIdempotentAction(action)) {
496:             val kept = ArrayDeque<String>()
497:             while (pendingCommands.isNotEmpty()) {
498:                 val existing = pendingCommands.removeFirst()
499:                 val existingAction = extractAction(existing)
500:                 if (existingAction == action) continue
501:                 kept.addLast(existing)
502:             }
503:             pendingCommands.addAll(kept)
504:         }
505: 
506:         while (pendingCommands.size >= maxPendingCommands) {
507:             if (pendingCommands.isNotEmpty()) {
508:                 pendingCommands.removeFirst()
509:             }
510:         }
511:         pendingCommands.addLast(payload)
512:     }
