16:     fun handleStateSync(event: RemoteEvent.StateSync, currentConversationId: String?) {
17:         val serverConversationId = event.conversationId
18:         
19:         if (!serverConversationId.isNullOrBlank() && serverConversationId != currentConversationId) {
20:             stateManager.clearAll()
