26:                 val lastLocal = state.messages.last()
27:                 val lastIncoming = messages.lastOrNull()
28:                 val canOverlayLocalAssistant = shouldOverlayLocalAssistant(lastLocal, lastIncoming)
29: 
30:                 if (canOverlayLocalAssistant) {
31:                     messages.dropLast(1) + lastLocal
32:                 } else messages
33:             } else messages
34: 
35:             // Keep optimistic user prompt visible while streaming until server echo catches up.
36:             if (event.isStreaming && state.messages.isNotEmpty()) {
37:                 val localTrailingUsers = state.messages
38:                     .takeLastWhile { it.role == MessageRole.USER && it.content.isNotBlank() }
39: 
40:                 if (localTrailingUsers.isNotEmpty()) {
41:                     val incomingUsers = finalMessages
