43:                         .filter { it.role == MessageRole.USER }
44:                         .take(12)
45:                         .map { AntigravityMessageMapper.normalizeUserText(it.content) }
46:                         .toSet()
47: 
48:                     val missingUsers = localTrailingUsers.filter {
49:                         val normalized = AntigravityMessageMapper.normalizeUserText(it.content)
50:                         normalized.isNotBlank() && normalized !in incomingUsers
51:                     }
52: 
53:                     if (missingUsers.isNotEmpty()) {
54:                         val lastAssistant = finalMessages.lastOrNull()?.takeIf { it.role == MessageRole.ASSISTANT }
55:                         finalMessages = if (lastAssistant != null) {
56:                             finalMessages.dropLast(1) + missingUsers + lastAssistant
57:                         } else {
58:                             finalMessages + missingUsers
59:                         }
60:                     }
61:                 }
62:             }
